+    #[must_use]
+    pub fn resolve_env<F>(&self, mut lookup: F) -> HashMap<String, String>
+    where
+        F: FnMut(&str) -> Option<String>,
+    {
+        self.env
+            .iter()
+            .map(|(name, value)| {
+                let resolved = value
+                    .resolve(&mut lookup)
+                    .map_or_else(|_| value.as_source(), |resolved| resolved.value);
+                (name.clone(), resolved)
+            })
+            .collect()
+    }
