+                .collect(),
+            ..RunEnvironmentSettings::default()
+        }
+    }
+
+    #[test]
+    fn resolve_env_substitutes_env_tokens_via_lookup() {
+        let s = settings(&[("NODE_ENV", "{{ env.NODE_ENV }}"), ("STATIC", "value")]);
+        let resolved = s.resolve_env(|name| match name {
+            "NODE_ENV" => Some("test".to_string()),
+            _ => None,
+        });
